mapper.select:
SELECT COUNT(*)
FROM interaction_event
WHERE user_id = #{userId}
  AND topic_id = #{topicId}
  AND created_at >= #{startTime}

SELECT topic_id, interaction_type, COUNT(*) AS total_count
FROM interaction_event
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}
GROUP BY topic_id, interaction_type

SELECT topic_id,
       SUM(CASE interaction_type
               WHEN 1 THEN #{likeWeight}
               WHEN 2 THEN #{bookmarkWeight}
               WHEN 3 THEN #{shareWeight}
               WHEN 5 THEN #{commentWeight}
               ELSE 0
           END * COALESCE(weight_multiplier, 1.0)) AS weighted_score,
       COUNT(*) AS total_count
FROM interaction_event
GROUP BY topic_id

SELECT topic_id,
       SUM(CASE interaction_type
               WHEN 1 THEN #{likeWeight}
               WHEN 2 THEN #{bookmarkWeight}
               WHEN 3 THEN #{shareWeight}
               WHEN 5 THEN #{commentWeight}
               ELSE 0
           END * COALESCE(weight_multiplier, 1.0)) AS weighted_score,
       COUNT(*) AS total_count
FROM interaction_event
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}
GROUP BY topic_id

SELECT interaction_type, COUNT(*) AS total_count
FROM interaction_event
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}
GROUP BY interaction_type

SELECT COUNT(*)
FROM interaction_event
WHERE topic_id = #{topicId}
  AND created_at >= #{startTime}
  AND created_at < #{endTime}

SELECT COUNT(DISTINCT user_id)
FROM interaction_event
WHERE device_fingerprint = #{deviceFingerprint}
  AND created_at >= #{startTime}

SELECT COUNT(*)
FROM interaction_event
WHERE user_id = #{userId}
  AND device_fingerprint = #{deviceFingerprint}
  AND created_at >= #{startTime}
